INSERT INTO posts (id, title, content, category, author, city, date, likes_count, comments_count, tags) VALUES
('p1', '서울 성수동 카페 작업 스팟 추천', '성수동에서 한 달 작업하면서 찾은 최고의 카페들을 공유합니다. 기가 와이파이에 콘센트도 충분하고 조용한 분위기가 최고예요.', '정보공유', 'CodeNomad_K', '서울', '2026.03.15', 42, 8, ARRAY['성수동','카페추천','작업스팟']),
('p2', '제주 한달살이 준비 시 꼭 알아야 할 것', '제주 한달살이 세 번 경험하면서 알게 된 팁들을 정리했어요. 숙소 예약 타이밍, 렌트카 vs 대중교통 비교 등 실용적인 정보가 가득합니다.', '정보공유', 'IslandWorker', '제주', '2026.03.14', 87, 19, ARRAY['제주한달살이','준비','팁']),
('p3', '원격근무 중 슬럼프 어떻게 극복하셨나요?', '노마드 6개월차인데 요즘 동기부여가 많이 떨어졌어요. 루틴 유지가 너무 어렵고 집중도 안 되고... 비슷한 경험 있으신 분들 어떻게 극복하셨는지 궁금합니다.', '질문', 'RemoteDevBusan', '부산', '2026.03.13', 34, 24, ARRAY['번아웃','동기부여','노마드고민']),
('p4', '대전에서 AI 개발자로 살아가기', 'KAIST 근처에서 반년째 노마딩 중입니다. 연구자들과 카페에서 대화하다 보면 자연스럽게 최신 AI 트렌드를 흡수하게 돼요. 대전의 기술 생태계를 소개합니다.', '후기', 'KaistNeighbor', '대전', '2026.03.12', 56, 11, ARRAY['대전','AI','개발자']),
('p5', '프리랜서 세금 신고 대행 서비스 써본 분?', '올해 처음으로 종합소득세 신고를 직접 해야 하는데 너무 복잡해서요. 세금 신고 대행 서비스 써보신 분들 후기 부탁드립니다. 비용 대비 가치 있나요?', '질문', 'SeoulCoder99', '서울', '2026.03.11', 28, 15, ARRAY['세금','프리랜서','세무']),
('p6', '광주 국립아시아문화전당 작업 후기', '광주 ACC에서 처음 작업해봤는데 너무 좋았어요. 탁 트인 공간에 무료 와이파이, 조용한 분위기. 관광객도 많지 않아서 집중도 잘 됩니다.', '후기', 'NomadMom', '광주', '2026.03.10', 19, 5, ARRAY['광주','ACC','무료작업공간']),
('p7', '노마드 초보자가 가장 많이 하는 실수 5가지', '저도 처음엔 많이 헤맸는데 1년 지나니 패턴이 보이더라고요. 너무 많은 도시 욕심내기, 인터넷 체크 안 하기, 백업 작업공간 없이 이동하기 등 공유합니다.', '정보공유', 'SurfDev', '부산', '2026.03.09', 103, 31, ARRAY['초보','팁','실수']),
('p8', '인천 송도 한 달 살아본 솔직 후기', '서울 옆이지만 완전히 다른 느낌. 센트럴파크 주변 산책하며 미팅하고 카페에서 집중 작업. 외국 도시 느낌이라 기분 전환에 최고였어요.', '후기', 'SongdoWorker', '인천', '2026.03.08', 45, 9, ARRAY['인천','송도','한달살이']),
('p9', '좋은 코워킹 스페이스 고르는 기준이 뭔가요?', '도시마다 코워킹 스페이스를 새로 찾아야 하는데 항상 고민됩니다. 여러분만의 선택 기준이 있나요? 가격, 위치, 시설 중 어느 게 제일 중요한지도 궁금해요.', '질문', 'TechDaegu', '대구', '2026.03.07', 22, 17, ARRAY['코워킹','선택기준','팁']),
('p10', '부산에서 만난 노마드들 소개합니다', '지난 달 부산 노마드 밋업에서 만난 분들과 지금도 계속 교류 중이에요. 노마드 커뮤니티의 힘을 느낀 경험이었어요. 다들 밋업 많이 나오세요!', '자유', 'RemoteDevBusan', '부산', '2026.03.06', 38, 6, ARRAY['부산','밋업','커뮤니티']);
